class Solution {
public:
    bool canIWin(int maxChoosableInteger, int desiredTotal) {
        if ((1 + maxChoosableInteger) * maxChoosableInteger / 2 < desiredTotal) return false;
        int mask = (1 << maxChoosableInteger);
        vector<int> memo(mask, -1);
        return dfs(maxChoosableInteger, desiredTotal, 0, 0, memo);
    }

    bool dfs(int& maxChoosableInteger, int& desiredTotal, int state, int total, vector<int>& memo) {
        if (memo[state] != -1) return memo[state];
        for (int i = 0; i < maxChoosableInteger; ++i) {
            if ((state & (1 << i)) == 0) {
                if (total + i + 1 >= desiredTotal) return memo[state] = 1;
                if (!dfs(maxChoosableInteger, desiredTotal, state | (1 << i), total + i + 1, memo)) {
                    return memo[state] = 1;
                }
            }
        }
        return memo[state] = 0;
    }
};
